// Solution
function solve(widths) {
  let sum = 0;
  for (let width of widths) {
    sum += parseInt(width.replace('%', ''));
  }
  return sum <= 100 ? 'row' : 'row-reverse';
}

solutions.python:
class Solution:
  def solve(self, widths: List[str]) -> str:
    # Calculate the sum of the widths
    sum = sum(int(width.replace('%', '')) for width in widths)
    # Return the direction
    return 'row' if sum <= 100 else 'row-reverse'
